import React from 'react';
import './FooterStyle.css'; // Importa os estilos CSS
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faPaw, faEnvelope, faPhone,faAddressCard  } from '@fortawesome/free-solid-svg-icons';


const Icon = ({ className }) => <i className={`${className} icon-spacing`}></i>;

const Footer = () => {
  return (
    <footer className="footer">
      <div className="footer-content">
        
        <div className="footer-section">
          <h2 className="footer-title">
          <FontAwesomeIcon icon={faPaw}/> 
            Patas do Amanhã 
          </h2>
          <p className="footer-text">
            Somos uma organização sem fins lucrativos dedicada a ajudar animais abandonados e em situação de risco.
          </p>
        </div>

        <div className="footer-section">
          <h3 className="footer-subtitle">
          <FontAwesomeIcon icon={faAddressCard} />
             Contato
          </h3>
          <p className="footer-text">
            
          <FontAwesomeIcon icon={faEnvelope} /> Contato@patasdoamanha.org
          
          </p>
          <p className="footer-text">
            
          <FontAwesomeIcon icon={faPhone} /> (18) 99166-8880
          </p>
        </div>

      </div>
    </footer>
  );
};

export default Footer;
